  async queryVulnerabilities(query: string): Promise<any> {
    if (!this.aiEnabled) {
      return {
        error: 'AI not enabled',
        suggestion: 'Set OPENAI_API_KEY to enable natural language queries',
      };
    }

    try {
      // Use AI to convert natural language to structured query
      const queryPrompt = `
You are a database query assistant. Convert the user's natural language query into a structured filter object.

User Query: "${query}"

Available fields:
- severity: CRITICAL, HIGH, MEDIUM, LOW, INFORMATIONAL
- type: SQL_INJECTION, XSS, COMMAND_INJECTION, etc.
- status: OPEN, IN_PROGRESS, RESOLVED, FALSE_POSITIVE
- cvssScore: number (0-10)
- target.name: string
- target.environment: PRODUCTION, STAGING, DEVELOPMENT

Return JSON with:
- filters: Object with field names and values to filter by
- orderBy: Field to sort by (optional)
- limit: Number of results to return (default 50)
- interpretation: Human-readable explanation of what you understood

Examples:
"Show me all critical SQLi" -> {"filters": {"severity": "CRITICAL", "type": "SQL_INJECTION"}, "limit": 50}
"High severity bugs in production" -> {"filters": {"severity": "HIGH", "target": {"environment": "PRODUCTION"}}, "limit": 50}
`;

      const completion = await this.openai!.chat.completions.create({
        model: 'gpt-4-turbo-preview',
        messages: [
          {
            role: 'system',
            content: 'You are a database query assistant that converts natural language to structured queries.',
          },
          { role: 'user', content: queryPrompt },
        ],
        response_format: { type: 'json_object' },
      });

      const queryPlan = JSON.parse(completion.choices[0].message.content || '{}');

      // Build Prisma query from AI interpretation
      const prismaQuery: any = {
        where: queryPlan.filters || {},
        include: { target: true },
        take: queryPlan.limit || 50,
      };

      if (queryPlan.orderBy) {
        prismaQuery.orderBy = { [queryPlan.orderBy]: 'desc' };
      }

      // Execute query
      const vulnerabilities = await this.prisma.vulnerability.findMany(prismaQuery);

      return {
        query,
        interpretation: queryPlan.interpretation || 'Query processed',
        filters: queryPlan.filters,
        results: vulnerabilities,
        count: vulnerabilities.length,
      };
    } catch (error) {
      this.logger.error(`Natural language query failed: ${error.message}`);

      // Fallback to simple search
      const vulnerabilities = await this.prisma.vulnerability.findMany({
        include: { target: true },
        take: 50,
      });

      return {
        query,
        results: vulnerabilities,
        message: 'Fallback search - AI query processing failed',
        error: error.message,
      };
    }
  }

