async predictRiskScore(vulnerability: any): Promise<number> {
  // Multi-factor risk scoring algorithm
  // Considers: severity, CVSS, exploitability, environment, and age

  const severityWeights = {
    CRITICAL: 10,
    HIGH: 7,
    MEDIUM: 4,
    LOW: 1,
    INFORMATIONAL: 0,
  };

  const environmentWeights = {
    PRODUCTION: 1.5,
    STAGING: 1.2,
    DEVELOPMENT: 1.0,
  };

  // Base score from severity
  const baseScore = severityWeights[vulnerability.severity] || 0;

  // CVSS score factor (0-10 normalized to 0-1)
  const cvssMultiplier = vulnerability.cvssScore / 10;

  // Environment factor
  const envMultiplier = vulnerability.target?.environment 
    ? environmentWeights[vulnerability.target.environment] || 1.0
    : 1.0;

  // Age factor - older vulnerabilities are riskier if unpatched
  const ageInDays = vulnerability.createdAt 
    ? Math.floor((Date.now() - new Date(vulnerability.createdAt).getTime()) / (1000 * 60 * 60 * 24))
    : 0;
  const ageFactor = Math.min(1.3, 1 + (ageInDays / 100)); // Max 30% increase

  // Exploitability factor - check if public exploits exist
  const exploitabilityFactor = vulnerability.description?.toLowerCase().includes('exploit') ? 1.2 : 1.0;

  // Calculate final risk score
  const riskScore = baseScore * cvssMultiplier * envMultiplier * ageFactor * exploitabilityFactor * 10;

  // Normalize to 0-100 range
  return Math.min(100, Math.max(0, Math.round(riskScore)));
}

