async start(id: string) {
  const listener = await this.findOne(id);

  if (listener.status === ListenerStatus.ACTIVE) {
    throw new Error('Listener is already active');
  }

  const scannerUrl = process.env.SCANNER_AGENT_URL || 'http://localhost:8080';

  try {
    // Call Go scanner service to start the actual listener
    const response = await fetch(`${scannerUrl}/listener/start`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        listenerId: id,
        name: listener.name,
        type: listener.type,
        host: listener.host,
        port: listener.port,
        protocol: listener.protocol,
        payload: listener.payload,
        encoding: listener.encoding,
      }),
    });

    if (!response.ok) {
      const error = await response.text();
      throw new Error(`Failed to start listener: ${error}`);
    }

    const result = await response.json();

    // Update database with active status and process info
    const updatedListener = await this.prisma.listener.update({
      where: { id },
      data: { 
        status: ListenerStatus.ACTIVE,
        bindIp: result.bindIp || listener.bindIp,
      },
    });

    console.log(`[+] Listener ${updatedListener.name} started on ${updatedListener.host}:${updatedListener.port}`);
    console.log(`[+] Process ID: ${result.processId || 'N/A'}`);

    return updatedListener;
  } catch (error) {
    // If scanner service is unavailable, mark as error
    await this.prisma.listener.update({
      where: { id },
      data: { status: ListenerStatus.ERROR },
    });

    console.error(`[-] Failed to start listener: ${error.message}`);
    throw new Error(`Listener startup failed: ${error.message}. Ensure SCANNER_AGENT_URL is configured and the Go scanner service is running.`);
  }
}

