async stop(id: string) {
  const listener = await this.findOne(id);

  if (listener.status === ListenerStatus.INACTIVE) {
    throw new Error('Listener is already inactive');
  }

  const scannerUrl = process.env.SCANNER_AGENT_URL || 'http://localhost:8080';

  try {
    // Call Go scanner service to stop the actual listener
    const response = await fetch(`${scannerUrl}/listener/stop`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        listenerId: id,
        port: listener.port,
      }),
    });

    if (!response.ok) {
      const error = await response.text();
      throw new Error(`Failed to stop listener: ${error}`);
    }

    const result = await response.json();

    // Close all active connections in database
    await this.prisma.connection.updateMany({
      where: { 
        listenerId: id,
        lastSeen: {
          gte: new Date(Date.now() - 5 * 60 * 1000), // Active in last 5 minutes
        },
      },
      data: {
        lastSeen: new Date(), // Mark as disconnected
      },
    });

    // Update database with inactive status
    const updatedListener = await this.prisma.listener.update({
      where: { id },
      data: { status: ListenerStatus.INACTIVE },
    });

    console.log(`[-] Listener ${updatedListener.name} stopped`);
    console.log(`[-] Closed ${result.closedConnections || 0} active connections`);

    return updatedListener;
  } catch (error) {
    // Mark as error but don't throw - listener might already be stopped
    await this.prisma.listener.update({
      where: { id },
      data: { status: ListenerStatus.ERROR },
    });

    console.error(`[-] Failed to stop listener: ${error.message}`);
    throw new Error(`Listener shutdown failed: ${error.message}. The listener may already be stopped or the scanner service is unavailable.`);
  }
}

