private async logChanges(changes: ChangeDetection[]) {
  try {
    // Store changes in audit log for complete audit trail
    for (const change of changes) {
      await this.prisma.auditLog.create({
        data: {
          userId: 'SYSTEM',
          action: 'MONITORING_CHANGE_DETECTED',
          details: JSON.stringify({
            targetId: change.targetId,
            targetName: change.targetName,
            changeType: change.changeType,
            oldValue: change.oldValue,
            newValue: change.newValue,
            detectedAt: change.detectedAt,
            severity: this.determineChangeSeverity(change),
          }),
        },
      });
    }

    this.logger.log(`Logged ${changes.length} changes to audit trail`);
  } catch (error) {
    this.logger.error(`Failed to log changes: ${error.message}`);
  }
}

/**
 * Determine severity of detected change
 */
private determineChangeSeverity(change: ChangeDetection): string {
  if (change.changeType === 'NEW_VULNERABILITIES') {
    const count = change.newValue - change.oldValue;
    if (count >= 5) return 'HIGH';
    if (count >= 2) return 'MEDIUM';
    return 'LOW';
  }
  if (change.changeType === 'SEVERITY_CHANGES') {
    return 'MEDIUM';
  }
  return 'LOW';
}

