private async sendSlackNotification(target: any, vulnerabilities: any[]) {
  const slackWebhookUrl = process.env.SLACK_WEBHOOK_URL;

  if (!slackWebhookUrl) {
    return; // Slack not configured
  }

  try {
    const criticalCount = vulnerabilities.filter(v => v.severity === 'CRITICAL').length;
    const highCount = vulnerabilities.filter(v => v.severity === 'HIGH').length;

    const message = {
      text: `🚨 *New Vulnerabilities Detected*`,
      blocks: [
        {
          type: 'header',
          text: {
            type: 'plain_text',
            text: '🚨 Security Alert: New Vulnerabilities',
          },
        },
        {
          type: 'section',
          fields: [
            {
              type: 'mrkdwn',
              text: `*Target:*\n${target.name}`,
            },
            {
              type: 'mrkdwn',
              text: `*Total Found:*\n${vulnerabilities.length}`,
            },
            {
              type: 'mrkdwn',
              text: `*Critical:*\n${criticalCount}`,
            },
            {
              type: 'mrkdwn',
              text: `*High:*\n${highCount}`,
            },
          ],
        },
        {
          type: 'section',
          text: {
            type: 'mrkdwn',
            text: `*Top Vulnerabilities:*\n${vulnerabilities.slice(0, 3).map(v => `• ${v.title} (${v.severity})`).join('\n')}`,
          },
        },
        {
          type: 'actions',
          elements: [
            {
              type: 'button',
              text: {
                type: 'plain_text',
                text: 'View Dashboard',
              },
              url: `${process.env.FRONTEND_URL}/dashboard`,
              style: 'primary',
            },
          ],
        },
      ],
    };

    const response = await fetch(slackWebhookUrl, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(message),
    });

    if (response.ok) {
      this.logger.log('Slack notification sent successfully');
    } else {
      this.logger.error(`Slack notification failed: ${response.statusText}`);
    }
  } catch (error) {
    this.logger.error(`Failed to send Slack notification: ${error.message}`);
  }
}

/**
 * Send webhook notification
 */
private async sendWebhookNotification(target: any, vulnerabilities: any[]) {
  const webhookUrl = process.env.WEBHOOK_URL;

  if (!webhookUrl) {
    return; // Webhook not configured
  }

  try {
    const payload = {
      event: 'vulnerabilities_detected',
      timestamp: new Date().toISOString(),
      target: {
        id: target.id,
        name: target.name,
        scope: target.scope,
      },
      vulnerabilities: vulnerabilities.map(v => ({
        title: v.title,
        type: v.type,
        severity: v.severity,
        cvssScore: v.cvssScore,
      })),
      summary: {
        total: vulnerabilities.length,
        critical: vulnerabilities.filter(v => v.severity === 'CRITICAL').length,
        high: vulnerabilities.filter(v => v.severity === 'HIGH').length,
        medium: vulnerabilities.filter(v => v.severity === 'MEDIUM').length,
        low: vulnerabilities.filter(v => v.severity === 'LOW').length,
      },
    };

    const response = await fetch(webhookUrl, {
      method: 'POST',
      headers: { 
        'Content-Type': 'application/json',
        'X-VulnX-Event': 'vulnerabilities_detected',
      },
      body: JSON.stringify(payload),
    });

    if (response.ok) {
      this.logger.log('Webhook notification sent successfully');
    } else {
      this.logger.error(`Webhook notification failed: ${response.statusText}`);
    }
  } catch (error) {
    this.logger.error(`Failed to send webhook notification: ${error.message}`);
  }
}

