  if (data.type === 'target') {
    bodyContent = `
      <h2>Target: ${data.target.name}</h2>
      <table>
        <tr><td><strong>Scope:</strong></td><td>${data.target.scope}</td></tr>
        <tr><td><strong>Type:</strong></td><td>${data.target.type}</td></tr>
        <tr><td><strong>Priority:</strong></td><td>${data.target.priority}</td></tr>
      </table>

      <h3>Vulnerabilities (${data.vulnerabilities.length})</h3>
      ${data.vulnerabilities.map((v: any) => `
        <div class="vulnerability ${v.severity.toLowerCase()}">
          <h4>${v.title}</h4>
          <p><span class="severity ${v.severity.toLowerCase()}">${v.severity}</span> CVSS: ${v.cvssScore}</p>
          <p><strong>Type:</strong> ${v.type}</p>
          <p><strong>Description:</strong> ${v.description}</p>
          <p><strong>Remediation:</strong> ${v.remediation}</p>
        </div>
      `).join('')}
    `;
  } else if (data.type === 'full') {
    bodyContent = `
      <h2>Full Security Report</h2>
      <p><strong>User:</strong> ${data.user.name} (${data.user.email})</p>

      <div class="summary-grid">
        <div class="summary-card">
          <div class="number">${data.summary.totalTargets}</div>
          <div class="label">Total Targets</div>
        </div>
        <div class="summary-card">
          <div class="number">${data.summary.totalVulnerabilities}</div>
          <div class="label">Total Vulnerabilities</div>
        </div>
        <div class="summary-card">
          <div class="number">${data.summary.criticalCount}</div>
          <div class="label">Critical</div>
        </div>
        <div class="summary-card">
          <div class="number">${data.summary.highCount}</div>
          <div class="label">High</div>
        </div>
      </div>

      <h3>Vulnerabilities by Target</h3>
      ${data.targets.filter((t: any) => t.vulnerabilities.length > 0).map((target: any) => `
        <h4>${target.name}</h4>
        <ul>
          ${target.vulnerabilities.map((v: any) => `
            <li><span class="severity ${v.severity.toLowerCase()}">${v.severity}</span> ${v.title} (CVSS: ${v.cvssScore})</li>
          `).join('')}
        </ul>
      `).join('')}
    `;
  }

  return `
    <!DOCTYPE html>
    <html>
    <head>
      <meta charset="UTF-8">
      <title>${title}</title>
      ${styles}
    </head>
    <body>
      <h1>${title}</h1>
      <div class="meta">Generated: ${new Date().toISOString()}</div>
      ${bodyContent}
      <div class="footer">
        Generated by VulnX Hunter - Automated Vulnerability Testing Platform
      </div>
    </body>
    </html>
  `;
}

private async initializeScheduledScans() {
  // Load scheduled scans from database on startup
  this.logger.log('Initializing scheduled scans...');

  try {
    // Query scheduled scans from database
    // Note: This requires a ScheduledScan table in the Prisma schema
    // For now, we'll check if the table exists and load if available

    const scheduledScans = await this.loadScheduledScansFromDatabase();

    for (const scan of scheduledScans) {
      try {
        // Recreate cron jobs for each scheduled scan
        const job = new CronJob(scan.schedule, async () => {
          this.logger.log(`Executing scheduled scan for target: ${scan.targetId}`);
          try {
            await this.scanService.triggerScan(scan.targetId, scan.userId);

            // Update last run time in database
            await this.updateLastRunTime(scan.id);

            this.logger.log(`Scheduled scan completed for target: ${scan.targetId}`);
          } catch (error) {
            this.logger.error(`Scheduled scan failed: ${error.message}`);
          }
        });

        if (scan.enabled) {
          this.schedulerRegistry.addCronJob(scan.id, job);
          job.start();
          this.scheduledScans.set(scan.id, job);

          this.logger.log(`Restored scheduled scan: ${scan.id} (${scan.schedule})`);
        }
      } catch (error) {
        this.logger.error(`Failed to restore scheduled scan ${scan.id}: ${error.message}`);
      }
    }

    this.logger.log(`Scheduled scans initialized: ${scheduledScans.length} scans loaded`);
  } catch (error) {
    this.logger.warn(`Could not load scheduled scans from database: ${error.message}`);
    this.logger.warn('Scheduled scans will be created on-demand');
  }
}

private async loadScheduledScansFromDatabase(): Promise<any[]> {
  try {
    // Attempt to load from database
    // This will work once the ScheduledScan model is added to Prisma schema
    const scans = await this.prisma.$queryRaw`
      SELECT * FROM "ScheduledScan" WHERE enabled = true
    `;
    return scans as any[];
  } catch (error) {
    // Table doesn't exist yet - return empty array
    return [];
  }
}

private async updateLastRunTime(scanId: string): Promise<void> {
  try {
    await this.prisma.$executeRaw`
      UPDATE "ScheduledScan" 
      SET "lastRun" = NOW() 
      WHERE id = ${scanId}
    `;
  } catch (error) {
    this.logger.error(`Failed to update last run time: ${error.message}`);
  }
}

